        'purchase_error' => 'Une erreur est survenue. Veuillez réessayer.',
        'officer_commander_title' => 'Commandant',
        'officer_commander_description' => 'Mener à bout une guerre est quasiment impossible de nos jours sans commandant. Les ordres sont effectués plus rapidement grâce à des commandes simplifiées. Ainsi, vous restez toujours informé de ce qui se passe dans votre empire ! Vous pourrez développer des stratégies vous permettant d`avoir toujours un coup d`avance sur votre adversaire.',
        'officer_commander_benefits' => 'Avec le Commandant, vous aurez un aperçu de l\'ensemble de l\'empire, un emplacement de mission supplémentaire et la possibilité de définir l\'ordre des ressources pillées.',
        'officer_commander_benefit_favourites' => '+40 favoris',
        'officer_commander_benefit_queue' => 'Liste de construction',
        'officer_commander_benefit_scanner' => 'Scanner de cargaison',
        'officer_commander_benefit_ads' => 'Absence de publicité',
        'officer_commander_tooltip' => '<b>+40 favoris</b><p>Avec plus de favoris, il est possible d`enregistrer plus de messages qui peuvent être partagés.</p><br/><b>Liste de construction</b><p>Placez jusqu`à 4 bâtiments ou recherches supplémentaires dans la liste.</p><br/><b>Scanner de cargaison</b><p>Le nombre de ressources que les transporteurs apportent sur vos planètes sera affiché.</p><br/><b>Absence de publicité</b><p>Fini la publicité pour d`autres jeux, vous ne recevrez plus que des informations sur les actions et évènements OGame.</p>',
        'officer_admiral_title' => 'Amiral',
        'officer_admiral_description' => 'L`amiral de la flotte est un vétéran aguerri et un stratège accompli. Même lorsque le combat est acharné, il garde le sang froid indispensable pour rester maitre de la situation et est en contact permanent avec les amiraux sous ses ordres. Un empereur avisé sait que son amiral de la flotte est primordial pour coordonner ses attaques, ce qui lui permet d`envoyer plus de flottes au combat simultanément. Il confère un emplacement d`expédition supplémentaire et peut déterminer quelles ressources charger en premier après une attaque. Par ailleurs, il accorde 20 emplacements de sauvegarde supplémentaires pour les simulations de combat.',
        'officer_admiral_benefits' => '+1 emplacement d\'expédition, possibilité de définir les priorités de ressources après une attaque, +20 emplacements de sauvegarde du simulateur de combat.',
        'officer_admiral_benefit_fleet_slots' => 'Nombre de flottes max. +2',
        'officer_admiral_benefit_expeditions' => 'Max. d`expéditions +1',
        'officer_admiral_benefit_escape' => 'Taux de fuite des flottes amélioré',
        'officer_admiral_benefit_save_slots' => 'Sauvegardes max +20',
        'officer_admiral_tooltip' => '<b>Nombre de flottes max. +2</b><p>Vous pouvez envoyer plus de flottes en même temps. </p><br/><b>Max. d`expéditions +1</b><p>Vous obtenez un emplacement d`expédition supplémentaire.</p><br/><b>Taux de fuite des flottes amélioré</b><p>Jusqu`à ce que vous ayez atteint 500.000 points, votre flotte peut fuir si l`ennemi lui est 3 fois supérieur.</p><br/><b>Sauvegardes max +20</b><p>Vous pouvez sauvegarder plus de simulations de combat en simultané</p>',
        'officer_engineer_title' => 'Ingénieur',
        'officer_engineer_description' => 'L`ingénieur est un spécialiste de la gestion d`énergie. En temps de paix, il optimise l`efficacité des réseaux d`énergie des colonies. En cas d`attaque, il coordonne l`alimentation en énergie des systèmes critiques de la défense planétaire et réduit les surtensions, ce qui réduit le nombre d`unités complètement détruites lors du combat',
        'officer_engineer_benefits' => '+10% d\'énergie produite sur toutes les planètes, 50% des défenses détruites survivent au combat.',
        'officer_engineer_benefit_defence' => 'Réduit de moitié les dommages infligés aux installations de défense',
        'officer_engineer_benefit_energy' => '+10% Production d`énergie',
        'officer_engineer_tooltip' => '<b>Réduit de moitié les dommages infligés aux installations de défense</b><p>Après un combat, la moitié des installations de défense perdues seront réparées.</p><br/><b>+10% Production d`énergie</b><p>Vos centrales et vos satellites solaires produisent 10 % d`énergie en plus.</p>',
        'officer_geologist_title' => 'Géologue',
        'officer_geologist_description' => 'Le géologue est un expert reconnu en astrominéralogie et en astrocristallographie. Avec son équipe d`experts en métallurgie et d`ingénieurs chimiste, il assiste les gouvernements interplanétaires dans la recherche de nouvelles sources de matières premières et optimise le raffinage de celles-ci.',
        'officer_geologist_benefits' => '+10% de production de métal, cristal et deutérium sur toutes les planètes.',
        'officer_geologist_benefit_mines' => '+10 % de prod. des mines',
        'officer_geologist_tooltip' => '<b>+10 % de prod. des mines</b><p>Vos mines produisent 10 % de plus.</p>',
        'officer_technocrat_title' => 'Technocrate',
        'officer_technocrat_description' => 'Les guildes de technocrates sont des scientifiques au génie reconnu. On les trouve aux endroits où la technologie est poussée au delà de ses limites. Personne ne parviendra à déchiffrer le cryptage d`un technocrate, sa seule présence inspire les chercheurs de tout l`empire.',
        'officer_technocrat_benefits' => '-25% de temps de recherche sur toutes les technologies.',
        'officer_technocrat_benefit_espionage' => '+2 Niveau d`espionnage',
        'officer_technocrat_benefit_research' => '25% Réduction des temps de recherche',
        'officer_technocrat_tooltip' => '<b>+2 Niveau d`espionnage</b><p>2 niveau sera ajouté à votre recherche d`espionnage.</p><br/><b>25% Réduction des temps de recherche</b><p>Vos recherches nécessiteront 25% de temps en moins pour leur achèvement.</p>',
        'officer_all_officers_title' => 'Conseil d`officiers',
        'officer_all_officers_description' => 'Avec le paquet promotionnel, vous accueillez à bord non seulement un spécialiste mais aussi tout un équipage. Vous obtenez tous les effets de chaque officier ainsi que des avantages supplémentaires que seul le pack complet garantit.\nPendant que le commandant, expert en stratégie, dirige les opérations, les officiers s`occupent de la gestion de l`énergie, de l`alimentation du système, de la mise en valeur des matières premières et du raffinage. En outre, ils accélèrent l`avancement des recherches et apportent leur expérience militaire lors des batailles épiques.',
        'officer_all_officers_benefits' => 'Tous les avantages du Commandant, de l\'Amiral, de l\'Ingénieur, du Géologue et du Technocrate, plus des bonus exclusifs disponibles uniquement avec le pack complet.',
